import{_ as a,o as r,c as e,a4 as d}from"./chunks/framework.BybBnFXO.js";const p=JSON.parse('{"title":"Trigonal","description":"","frontmatter":{"title":"Trigonal","crystalSystem":"trigonal"},"headers":[],"relativePath":"classification/crystal-systems/trigonal.md","filePath":"classification/crystal-systems/trigonal.md","lastUpdated":1784176423000}'),i={name:"classification/crystal-systems/trigonal.md"};function o(l,t,s,n,h,c){return r(),e("div",null,[...t[0]||(t[0]=[d('<h1 id="trigonal" tabindex="-1">Trigonal <a class="header-anchor" href="#trigonal" aria-label="Permalink to &quot;Trigonal&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>The trigonal system has a 3-fold rather than 6-fold principal axis (no horizontal mirror plane perpendicular to it). Crystals are uniaxial. Corundum, quartz, and tourmaline are the most important gem families. Twinning is very common and useful for identification (e.g., Dauphiné / Japan law in quartz).</p><h2 id="crystallographic-parameters" tabindex="-1">Crystallographic Parameters <a class="header-anchor" href="#crystallographic-parameters" aria-label="Permalink to &quot;Crystallographic Parameters&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Property</th><th>Value</th></tr></thead><tbody><tr><td>Axial lengths</td><td>a₁ = a₂ = a₃ ≠ c (rhombohedral subtype)</td></tr><tr><td>Interaxial angles</td><td>as hexagonal</td></tr><tr><td>Symmetry tier</td><td>medium-high</td></tr><tr><td>Optical class</td><td>uniaxial</td></tr><tr><td>Optic sign</td><td>+ or − (varies)</td></tr><tr><td>Birefringence</td><td>0.000–0.116</td></tr><tr><td>Cleavage</td><td>variable</td></tr><tr><td>Habit</td><td>Rhombohedra, scalenohedra, prismatic with striations</td></tr></tbody></table><h2 id="notable-gem-species" tabindex="-1">Notable Gem Species <a class="header-anchor" href="#notable-gem-species" aria-label="Permalink to &quot;Notable Gem Species&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Gem</th><th>Refractive Index</th><th>Specific Gravity</th></tr></thead><tbody><tr><td>Ruby (Corundum)</td><td>1.762–1.770</td><td>3.97–4.05</td></tr><tr><td>Sapphire (Corundum)</td><td>1.762–1.778</td><td>3.95–4.03</td></tr><tr><td>Quartz (Crystalline)</td><td>1.544–1.553</td><td>2.65</td></tr><tr><td>Amethyst / Citrine</td><td>1.544–1.553</td><td>2.65</td></tr><tr><td>Tourmaline</td><td>1.614–1.666</td><td>3.06–3.20</td></tr><tr><td>Rhodochrosite</td><td>1.600–1.820</td><td>3.45–3.70</td></tr><tr><td>Phenakite</td><td>1.650–1.670</td><td>2.93–2.97</td></tr><tr><td><em>See the <a href="./../intro.html">classification overview</a> for all crystal systems.</em></td><td></td><td></td></tr></tbody></table>',7)])])}const u=a(i,[["render",o]]);export{p as __pageData,u as default};
